    if (rl->curr_rec < rl->num_recs // Ensure all records have been processed
        || rl->curr_rec != rl->num_released // Ensure all records have been released
        || TLS_BUFFER_get_left(&rl->rbuf) != 0 // Ensure the buffer is empty
        || rl->rstate == SSL_ST_READ_BODY) // Ensure the buffer is not actively being read
        return 0; // Return 0 indicating an error

    // Release the read buffer if no pending data
    return tls_release_read_buffer(rl); // Return the result of releasing the read buffer
}

